urlset:


    https://{{ domain }}/
    {% now "Y-m-d" %}
    daily
    1.0




    https://{{ domain }}/about/
    {% now "Y-m-d" %}
    monthly
    0.8



    https://{{ domain }}/contact/
    {% now "Y-m-d" %}
    monthly
    0.8




    https://{{ domain }}/deals/
    {% now "Y-m-d" %}
    daily
    0.9




    https://{{ domain }}/deals/hot-deals/
    {% now "Y-m-d" %}
    daily
    0.9




    https://{{ domain }}/deals/featured/
    {% now "Y-m-d" %}
    daily
    0.9



{% for category in categories %}

    https://{{ domain }}{{ category.get_absolute_url }}
    {{ category.updated_at|date:"Y-m-d" }}
    weekly
    0.7

{% endfor %}


{% for product in products %}

    https://{{ domain }}{{ product.get_absolute_url }}
    {{ product.updated_at|date:"Y-m-d" }}
    weekly
    0.8

{% endfor %}
